#!/usr/bin/env node
/**
 * check-source-integrity.cjs
 *
 * Defends against Cowork-mount file corruption. Two checks:
 *   1. Null bytes in source files (the classic symptom).
 *   2. Strict JSON files parse correctly (catches mid-content truncation).
 *
 * Files known to use JSON-with-comments (jsonc) are skipped from the parse check:
 *   - tsconfig*.json (TypeScript convention)
 *   - .vscode/*.json (editor settings)
 *   - package-lock.json (auto-generated by npm)
 *
 * Cross-platform Node implementation — runs anywhere Node runs (Windows
 * PowerShell, macOS, Linux). No shell dependency.
 *
 * Exit 0 if clean, 1 if any file is corrupted.
 *
 * Usage:
 *   node scripts/check-source-integrity.cjs            # all tracked source files
 *   node scripts/check-source-integrity.cjs --staged   # staged files only (used by pre-commit hook)
 */

const { execSync } = require('child_process');
const fs = require('fs');

const SOURCE_EXT = /\.(ts|tsx|js|jsx|cjs|mjs|json|md|sql|yml|yaml|html|css|sh)$/i;
const STRICT_JSON_SKIP = [
    /(^|\/)tsconfig[^/]*\.json$/,
    /(^|\/)\.vscode\/.*\.json$/,
    /(^|\/)package-lock\.json$/,
];

function isStrictJsonSkip(path) {
    return STRICT_JSON_SKIP.some(re => re.test(path));
}

function listFiles(staged) {
    let out;
    if (staged) {
        out = execSync('git diff --cached --name-only --diff-filter=ACM', { encoding: 'utf8' });
    } else {
        out = execSync('git ls-files', { encoding: 'utf8' });
    }
    return out.split(/\r?\n/).filter(p => p && SOURCE_EXT.test(p));
}

function hasNullBytes(buf) {
    return buf.includes(0);
}

function countNullBytes(buf) {
    let n = 0;
    for (let i = 0; i < buf.length; i++) if (buf[i] === 0) n++;
    return n;
}

function main() {
    const staged = process.argv.includes('--staged');

    let files;
    try {
        files = listFiles(staged);
    } catch (err) {
        console.error('check-source-integrity: failed to list files via git:', err.message);
        process.exit(1);
    }

    if (files.length === 0) {
        console.log('check-source-integrity: no source files to scan');
        process.exit(0);
    }

    const nullCorrupted = [];
    const jsonCorrupted = [];
    let scanned = 0;

    for (const f of files) {
        if (!fs.existsSync(f) || !fs.statSync(f).isFile()) continue;
        scanned++;

        const buf = fs.readFileSync(f);

        if (hasNullBytes(buf)) {
            nullCorrupted.push(`${f} (${countNullBytes(buf)} null bytes)`);
            continue;
        }

        if (f.toLowerCase().endsWith('.json') && !isStrictJsonSkip(f)) {
            try {
                JSON.parse(buf.toString('utf8'));
            } catch {
                jsonCorrupted.push(f);
            }
        }
    }

    const total = nullCorrupted.length + jsonCorrupted.length;
    if (total > 0) {
        if (nullCorrupted.length > 0) {
            console.error(`check-source-integrity: ${nullCorrupted.length} file(s) contain null bytes:`);
            for (const e of nullCorrupted) console.error(`   - ${e}`);
        }
        if (jsonCorrupted.length > 0) {
            console.error(`check-source-integrity: ${jsonCorrupted.length} JSON file(s) fail to parse (likely truncated):`);
            for (const e of jsonCorrupted) console.error(`   - ${e}`);
        }
        console.error('');
        console.error('These files are corrupted (likely from a Cowork sandbox Write/Edit on the Windows mount).');
        console.error('Repair by rewriting via scripts/safe-write.py:');
        console.error('    cat /tmp/clean-content | python3 scripts/safe-write.py path/to/file');
        process.exit(1);
    }

    console.log(`check-source-integrity: ${scanned} files scanned, 0 corrupted`);
    process.exit(0);
}

main();
